@@ -15394,7 +15394,14 @@ Value *BoUpSLP::vectorizeTree(TreeEntry *E, bool PostponedPHIs) {
         if (SrcIt != MinBWs.end())
           SrcBWSz = SrcIt->second.first;
         unsigned BWSz = DL->getTypeSizeInBits(ScalarTy->getScalarType());
-        if (BWSz == SrcBWSz) {
+        // Don't convert extensions to BitCast when signedness matters.
+        // For example, zext i16 -1 to i32 produces 65535, not -1.
+        // If we convert to BitCast and demote to i16, we get -1 back,
+        // which changes semantics for signed comparisons.
+        bool IsZExt = VecOpcode == Instruction::ZExt;
+        bool IsSExt = VecOpcode == Instruction::SExt;
+        bool PreserveExtension = (IsZExt || IsSExt) && (It != MinBWs.end() || SrcIt != MinBWs.end());
+        if (BWSz == SrcBWSz && !PreserveExtension) {
           VecOpcode = Instruction::BitCast;
         } else if (BWSz < SrcBWSz) {
           VecOpcode = Instruction::Trunc;
EOF
```

